import fitz, sys
sys.stdout.reconfigure(encoding='utf-8', errors='replace')
doc = fitz.open(r'C:\Users\Administrator\Desktop\DAEHYUN_PRIVATE\TM Robot\Software-Manual-TMflow_SW2.18_Rev1.02_EN.pdf')
# Remote control settings лҳҗлҠ” TMflow UIм—җм„ң ESTOP н•ҙм ңн•ҳлҠ” л°©лІ• кІҖмғү
for i in range(doc.page_count):
    page = doc[i]
    text = page.get_text()
    if 'Remote Control' in text and ('setting' in text.lower() or 'external' in text.lower()):
        print(f'--- PAGE {i+1} ---')
        lines = text.split('\n')
        for j, line in enumerate(lines):
            if any(kw in line for kw in ['Remote Control', 'AUT.P', 'Stick Control', 'external', 'PLAY', 'STOP', 'reset', 'Reset']):
                start = max(0, j-1)
                end = min(len(lines), j+3)
                for k in range(start, end):
                    print(f'  {lines[k]}')
                print('  ---')
